import React, { useState, useEffect } from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ credentials, closeSidebar, handleSelectUserStory }) {
  const [project, setProject] = useState('');
  const [issueType, setIssueType] = useState('');
  const [jiraData, setJiraData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [isSidebarVisible, setIsSidebarVisible] = useState(true); // Add state to manage visibility

  // If credentials are not passed, show error message
  useEffect(() => {
    if (!credentials) {
      setError('Credentials not found');
    }
  }, [credentials],
     console.log(credentials));

  // Fetch Jira user stories based on domain, project, and issue type
  const fetchJiraData = async () => {
    if (!credentials || !credentials.domain) {
      setError('Invalid credentials. Domain is required.');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const response = await fetch(
        `https://localhost:7216/api/UserStoryDescription/ExportAllUserStories?domain=${credentials.domain}&project=${project}&issueType=${issueType}`
      );

      if (!response.ok) {
        throw new Error('Failed to fetch Jira data.');
      }

      const data = await response.json();
      setJiraData(data); // Set the fetched data
    } catch (err) {
      setError(err.message); // Show error message if something fails
    } finally {
      setLoading(false);
    }
  };

  // Handle selecting a user story from the list
  const handleStorySelect = (story) => {
    handleSelectUserStory(story); // Pass the selected story to the parent component
    closeSidebar(); // Close the sidebar after selection
  };

  // Toggle the sidebar visibility
  const toggleSidebar = () => {
    setIsSidebarVisible((prevVisibility) => !prevVisibility);
  };

  return (
    <div className={`import-sidebar ${isSidebarVisible ? 'visible' : ''}`}> {/* Toggle the class dynamically */}
      {/* Close button */}
      <button className="close-btn" onClick={closeSidebar}>X</button>
      <div className="sidebar-title"><strong>Fetch Jira User Stories</strong></div>

      {/* Input fields for project and issue type */}
      <div className="input-fields">
        <input
          type="text"
          placeholder="Domain"
          value={credentials ? credentials.domain : ''}
          disabled
        />
        <input
          type="text"
          placeholder="Project"
          value={project}
          onChange={(e) => setProject(e.target.value)}
        />
        <input
          type="text"
          placeholder="Issue Type"
          value={issueType}
          onChange={(e) => setIssueType(e.target.value)}
        />
      </div>

      {/* Fetch Jira user stories button */}
      <button className="fetch-btn" onClick={fetchJiraData} disabled={loading || !credentials}>
        {loading ? 'Loading...' : 'Fetch User Stories'}
      </button>

      {/* Error message */}
      {error && <div className="error-message">{error}</div>}

      {/* List of Jira data (user stories) */}
      <div className="jira-data">
        {jiraData.length > 0 ? (
          <ul>
            {jiraData.map((story, index) => (
              <li key={index} onClick={() => handleStorySelect(story)}>
                {story.title}
              </li>
            ))}
          </ul>
        ) : (
          <p>No user stories found.</p>
        )}
      </div>

      {/* Import Sidebar Button */}
      <button className="import-button" onClick={toggleSidebar}>
        &#x2190; {/* Arrow character */}
      </button>
    </div>
  );
}

export default ImportDataSidebar;
